 2→
 3→/**
 4→ * Runtime-validated environment configuration.
 5→ * Fails fast on startup if required vars are missing.
 6→ */
 7→const envSchema = z.object({
 8→  // Core
 9→  NODE_ENV: z.enum(['development', 'production', 'test']).default('development'),
10→  NEXT_PUBLIC_APP_URL: z.string().url().default('http://localhost:3000'),
11→  APP_SECRET: z.string().min(8).default('change-me-to-a-random-secret'),
12→
13→  // Database
14→  DATABASE_URL: z.string().default('postgresql://sandra:sandra@localhost:5432/sandra?schema=public'),
15→
16→  // OpenAI
17→  OPENAI_API_KEY: z.string().default(''),
18→  OPENAI_MODEL: z.string().default('gpt-4o'),
19→  OPENAI_EMBEDDING_MODEL: z.string().default('text-embedding-3-small'),
20→
21→  // GitHub
22→  GITHUB_TOKEN: z.string().default(''),
23→  GITHUB_ORG: z.string().default('edlinitiative'),
24→
25→  // Vector Store
26→  VECTOR_STORE_PROVIDER: z.enum(['memory', 'pinecone', 'qdrant', 'weaviate']).default('memory'),
27→  VECTOR_STORE_URL: z.string().optional(),
28→  VECTOR_STORE_API_KEY: z.string().optional(),
29→
30→  // Logging
31→  LOG_LEVEL: z.enum(['debug', 'info', 'warn', 'error']).default('info'),
32→});
33→
34→export type Env = z.infer<typeof envSchema>;
35→
36→function loadEnv(): Env {
37→  const parsed = envSchema.safeParse(process.env);
38→
39→  if (!parsed.success) {
40→    console.error('❌ Invalid environment variables:');
41→    for (const issue of parsed.error.issues) {
42→      console.error(`  ${issue.path.join('.')}: ${issue.message}`);
43→    }
44→    // In development, continue with defaults; in production, fail hard
45→    if (process.env.NODE_ENV === 'production') {
46→      throw new Error('Missing required environment variables');
47→    }
48→    // Return parsed data with defaults applied
49→    return envSchema.parse({});
50→  }
51→
52→  return parsed.data;
53→}
54→
55→export const env = loadEnv();
