 48→  return !key || key.length < 10 || key.startsWith('sk-your') || key === 'change-me';
 49→}
 50→
 51→export async function POST(request: Request) {
 52→  try {
 53→    const body = await request.json();
 54→    const parsed = chatRequestSchema.safeParse(body);
 55→
 56→    if (!parsed.success) {
 57→      return NextResponse.json(
 58→        {
 59→          error: {
 60→            code: 'VALIDATION_ERROR',
 61→            message: 'Invalid request',
 62→            issues: parsed.error.issues.map((i) => ({
 63→              field: i.path.join('.'),
 64→              message: i.message,
 65→            })),
 66→          },
 67→        },
 68→        { status: 400 },
 69→      );
 70→    }
 71→
 72→    const { message, userId, channel } = parsed.data;
 73→    const sessionId = parsed.data.sessionId ?? crypto.randomUUID();
 74→    const language = resolveLanguage(parsed.data.language);
 75→
 76→    // Demo mode: return canned response when API key is not configured
 77→    if (isApiKeyMissing()) {
 78→      return NextResponse.json({
 79→        data: {
 80→          response: getDemoResponse(message, language),
 81→          sessionId,
 82→          language,
 83→          toolsUsed: [],
 84→          retrievalUsed: false,
 85→          demoMode: true,
 86→          usage: { promptTokens: 0, completionTokens: 0, totalTokens: 0 },
 87→        },
 88→      });
 89→    }
 90→
 91→    const result = await runSandraAgent({
 92→      message,
 93→      sessionId,
 94→      userId,
 95→      language,
 96→      channel,
 97→    });
 98→
 99→    return NextResponse.json({
100→      data: {
101→        response: result.response,
102→        sessionId,
103→        language: result.language,
104→        toolsUsed: result.toolsUsed,
105→        retrievalUsed: result.retrievalUsed,
106→        usage: result.tokenUsage,
107→      },
108→    });
109→  } catch (error) {
110→    // If the error is a provider auth error, fall back to demo mode gracefully
111→    const isAuthError =
112→      error instanceof SandraError &&
113→      error.code === 'PROVIDER_ERROR' &&
114→      error.message.includes('401');
115→
116→    if (isAuthError) {
117→      const body = chatRequestSchema.safeParse(await request.clone().json().catch(() => ({})));
118→      const language = body.success ? resolveLanguage(body.data.language) : 'en';
119→      const message = body.success ? body.data.message : '';
120→      return NextResponse.json({
121→        data: {
122→          response: getDemoResponse(message, language),
123→          sessionId: body.success ? body.data.sessionId ?? crypto.randomUUID() : crypto.randomUUID(),
124→          language,
125→          toolsUsed: [],
126→          retrievalUsed: false,
127→          demoMode: true,
128→          usage: { promptTokens: 0, completionTokens: 0, totalTokens: 0 },
129→        },
130→      });
131→    }
132→
133→    const err = errorResponse(error);
134→    return NextResponse.json({ error: err.error }, { status: err.status });
135→  }
136→}
